     5→//! Tests for vvcg_guard module
     6→//!
     7→//! Unit tests for guard cost model and integration test for the full guard workflow.
     8→//! These tests avoid std::env::set_current_dir() to prevent race conditions in parallel test runs.
     9→
    10→#[cfg(test)]
    11→mod tests {
    12→    use crate::vvcg_guard::{zvvcg_get_diff_size, vvcg_run, vvcg_GuardArgs, VVCG_SIZE_LIMIT, VVCG_WARN_LIMIT};
    13→    use std::fs;
    14→    use std::path::{Path, PathBuf};
    15→    use std::process::Command;
    16→
    17→    /// Get test temp directory - uses BUD if available, falls back to system temp
    18→    fn get_test_base() -> PathBuf {
    19→        // Try to use BUD temp dir if available (when run via tabtarget)
    20→        if let Ok(bud_temp) = std::env::var("BUD_TEMP_DIR") {
    21→            let path = PathBuf::from(bud_temp);
    22→            // Canonicalize to absolute path (BUD_TEMP_DIR may be relative)
    23→            path.canonicalize().unwrap_or(path)
    24→        } else {
    25→            // Fall back to system temp for direct cargo test
    26→            std::env::temp_dir()
    27→        }
    28→    }
    29→
    30→    /// Helper to initialize a git repo in a directory
    31→    fn init_git_repo(dir: &Path) {
    32→        Command::new("git")
    33→            .args(["init"])
    34→            .current_dir(dir)
    35→            .output()
    36→            .expect("git init failed");
    37→
    38→        // Set user config for commits
    39→        Command::new("git")
    40→            .args(["config", "user.name", "Test User"])
    41→            .current_dir(dir)
    42→            .output()
    43→            .expect("git config user.name failed");
    44→
    45→        Command::new("git")
    46→            .args(["config", "user.email", "test@example.com"])
    47→            .current_dir(dir)
    48→            .output()
    49→            .expect("git config user.email failed");
    50→    }

